import * as fs from 'fs';
import * as path from 'path';
import * as os from 'os';

describe('dirty _flush backpressure guard', () => {
  it('should emit drain exactly once when set is called during backpressure', (done) => {
    const Dirty = require('../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js');
    const file = path.join(os.tmpdir(), `dirty-bp-${process.pid}.dirty`);
    try { fs.unlinkSync(file); } catch (e) { /* ignore */ }

    const db = new Dirty(file);
    let drainCount = 0;

    db.on('drain', () => { drainCount++; });

    db.on('load', () => {
      const ws = db._writeStream;
      let writeCallCount = 0;
      const pendingCbs: Array<(err: Error | null) => void> = [];

      // Replace write to simulate backpressure on first call
      ws.write = (data: any, cb: (err: Error | null) => void): boolean => {
        writeCallCount++;
        pendingCbs.push(cb);
        // First write returns false (backpressure), subsequent return true
        return writeCallCount > 1;
      };

      db.set('key1', 'val1');
      // Original: _waitForDrain=true, _inFlightWrites=1, pendingCbs=[cb1]
      // Mutation: same

      db.set('key2', 'val2');
      // Original: _flush() returns early (waitForDrain=true), queue={key2}
      // Mutation: _flush() proceeds, _inFlightWrites=2, pendingCbs=[cb1, cb2]

      // Capture which callbacks exist before stream drain fires
      const cbsBeforeDrain = [...pendingCbs];

      // Fire all pre-drain callbacks
      cbsBeforeDrain.forEach(cb => cb(null));
      // Original: only cb1 fired, _inFlightWrites=0, _waitForDrain=true → no drain
      // Mutation: cb1 and cb2 fired, last one: _inFlightWrites=0, _waitForDrain=false → drain (drainCount=1)

      // Simulate the write stream's drain event
      ws.emit('drain');
      // Original: _waitForDrain=false, queue={key2} → _flush() writes key2, _inFlightWrites=1
      // Mutation: _waitForDrain=false, queue empty, _inFlightWrites=0 → drain AGAIN (drainCount=2)

      // Fire any callbacks added by the drain handler (only in original)
      pendingCbs.slice(cbsBeforeDrain.length).forEach(cb => cb(null));
      // Original: cb2 fired, _inFlightWrites=0, _waitForDrain=false → drain (drainCount=1)
      // Mutation: no new callbacks

      setImmediate(() => {
        expect(drainCount).toBe(1);
        try { fs.unlinkSync(file); } catch (e) { /* ignore */ }
        done();
      });
    });
  });
});
